// Debug: সব data দেখো
const rawData = $input.first().json;
console.log('Raw input:', JSON.stringify(rawData));

// n8n webhook এ data আসে body তে অথবা সরাসরি
let senderId    = '';
let messageText = '';

// Try direct
if (rawData.senderId) {
  senderId    = rawData.senderId;
  messageText = rawData.messageText;
}
// Try body wrapper
else if (rawData.body && rawData.body.senderId) {
  senderId    = rawData.body.senderId;
  messageText = rawData.body.messageText;
}

console.log(`senderId: ${senderId}`);
console.log(`messageText: ${messageText}`);

if (!senderId || !messageText) {
  // Return with whatever we have for debugging
  return [{
    json: {
      senderId:    senderId    || 'NO_ID',
      messageText: messageText || 'NO_TEXT',
      rawData:     rawData
    }
  }];
}

return [{
  json: {
    senderId,
    messageText
  }
}];

const faqs = [
  {
    q: 'delivery কত দিন / ডেলিভারি / কখন পাবো / shipping',
    a: 'ডেলিভারি সময় ২-৩ কার্যদিবস। ঢাকার মধ্যে ১-২ দিন।'
  },
  {
    q: 'payment / পেমেন্ট / টাকা / বিকাশ / নগদ / COD / cash',
    a: 'আমরা Cash on Delivery (COD) গ্রহণ করি। পণ্য পেয়ে টাকা দিন।'
  },
  {
    q: 'কোথায় deliver / location / সারা বাংলাদেশ / জেলা / বাইরে',
    a: 'সারা বাংলাদেশে ডেলিভারি। ঢাকা, চট্টগ্রাম সহ সকল জেলায় সার্ভিস।'
  },
  {
    q: 'return / ফেরত / রিপ্লেসমেন্ট / খারাপ / নষ্ট / সমস্যা',
    a: 'পণ্য পাওয়ার ৩ দিনের মধ্যে সমস্যা হলে বিনামূল্যে রিপ্লেসমেন্ট।'
  },
  {
    q: 'quality / কোয়ালিটি / মান / আসল / original / নকল',
    a: 'সব পণ্য Premium Export Quality। ১০০% অরিজিনাল গ্যারান্টি।'
  }
];

const faqText = faqs
  .map((f, i) => `FAQ ${i+1}:\nপ্রশ্ন: ${f.q}\nউত্তর: ${f.a}`)
  .join('\n\n');

return [{
  json: {
    senderId:    $json.senderId,
    messageText: $json.messageText,
    faqContext:  faqText
  }
}];

const senderId    = $json.senderId;
const messageText = $json.messageText;
const faqContext  = $json.faqContext;

const systemPrompt = `তুমি ShopBot BD-এর বিনয়ী কাস্টমার সার্ভিস প্রতিনিধি।
Bangla ও English বুঝো, সবসময় বাংলায় উত্তর দাও।

আমাদের FAQ:
${faqContext}

নিয়ম:
১. সবসময় বাংলায় উত্তর দাও।
২. উত্তর সংক্ষিপ্ত রাখো, ২-৩ লাইন।
৩. বিনয়ী ও আন্তরিক ভাষায় কথা বলো।
৪. FAQ মিললে সেই উত্তর দাও।
৫. অজানা হলে বলো: আপনার প্রশ্নটি বুঝতে পারিনি, একটু বিস্তারিত বলবেন?`;

const payload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 300,
  temperature: 0.7,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: messageText }
  ]
};

return [{
  json: {
    senderId,
    messageText,
    groqPayload: JSON.stringify(payload)
  }
}];

const groqResponse = $input.first().json;
const prevData = $('5. Build Groq Payload').first().json;

const senderId = String(prevData.senderId).trim();

let replyText = 'দুঃখিত, এই মুহূর্তে উত্তর দিতে পারছি না। একটু পরে আবার চেষ্টা করুন। 🙏';

if (
  groqResponse.choices &&
  groqResponse.choices[0] &&
  groqResponse.choices[0].message &&
  groqResponse.choices[0].message.content
) {
  replyText = groqResponse.choices[0].message.content.trim();
}

console.log(`senderId: ${senderId}`);
console.log(`replyText: ${replyText}`);

return [{
  json: {
    senderId,
    replyText
  }
}];

const now = new Date().toLocaleString('en-BD', { timeZone: 'Asia/Dhaka' });
const senderId  = $('7. Extract Reply').first().json.senderId;
const replyText = $('7. Extract Reply').first().json.replyText;

console.log(`[${now}] SUCCESS - Replied to: ${senderId}`);
console.log(`Reply: ${replyText.substring(0, 100)}`);

return [{
  json: {
    success: true,
    timestamp: now,
    senderId,
    replyPreview: replyText.substring(0, 100)
  }
}];
